(function(){'use strict';var STORAGE_KEY='promoSuppressed';var SCROLL_THRESHOLD=0.5;document.addEventListener('DOMContentLoaded',function(){if(localStorage.getItem(STORAGE_KEY)==='true')return;var modal=document.querySelector('[data-promo-modal]');if(!modal)return;var suppressCheck=document.getElementById('promo-suppress');var hasTriggered=false;function openModal(){if(hasTriggered)return;hasTriggered=true;modal.removeAttribute('hidden');modal.setAttribute('aria-hidden','false');document.body.classList.add('landing12-no-scroll');}
function closeModal(){if(suppressCheck&&suppressCheck.checked){localStorage.setItem(STORAGE_KEY,'true');}
modal.setAttribute('hidden','');modal.setAttribute('aria-hidden','true');document.body.classList.remove('landing12-no-scroll');}
modal.addEventListener('click',function(e){if(e.target.closest('[data-promo-close]')){closeModal();}});document.addEventListener('keydown',function(e){if(e.key==='Escape'&&!modal.hasAttribute('hidden')){closeModal();}});var isLanding=!!document.querySelector('.landing12')||!!document.querySelector('[data-landing12]');var isTickets=!!document.querySelector('.tickets-page');if(isLanding){function onScroll(){var scrolled=window.scrollY;var docHeight=document.documentElement.scrollHeight-window.innerHeight;if(docHeight<=0)return;if(scrolled/docHeight>=SCROLL_THRESHOLD){window.removeEventListener('scroll',onScroll,{passive:true});openModal();}}
window.addEventListener('scroll',onScroll,{passive:true});}});}());